body:
    let mut analyzer = Self {
        patterns: HashMap::new(),
    };
    analyzer.initialize_patterns();
    analyzer
}

    // Public API patterns
    let public_api_patterns = vec![
        ApiPattern {
            _name: "Public Function".to_string(),
            pattern: Regex::new(r"(?m)^(pub\s+)?(?:async\s+)?fn\s+(\w+)\s*\([^)]*\)").unwrap(),
            element_type: "function".to_string(),
            visibility_pattern: Some(Regex::new(r"^pub\s+").unwrap()),
        },
        ApiPattern {
            _name: "Public Class".to_string(),
            pattern: Regex::new(r"(?m)^(pub\s+)?(?:class|struct)\s+(\w+)").unwrap(),
            element_type: "class".to_string(),
            visibility_pattern: Some(Regex::new(r"^pub\s+").unwrap()),
        },
        ApiPattern {
            _name: "Public Method".to_string(),
            pattern: Regex::new(
                r"(?m)^\s*(pub\s+)?(?:async\s+)?(?:def|fn)\s+(\w+)\s*\([^)]*\)",
            )
            .unwrap(),
            element_type: "method".to_string(),
            visibility_pattern: Some(Regex::new(r"^\s*pub\s+").unwrap()),
        },
        ApiPattern {
            _name: "Public Constant".to_string(),
            pattern: Regex::new(r"(?m)^(pub\s+)?const\s+(\w+)").unwrap(),
            element_type: "constant".to_string(),
            visibility_pattern: Some(Regex::new(r"^pub\s+").unwrap()),
        },
    ];
    self.patterns
        .insert("public_api".to_string(), public_api_patterns);

    // Versioning patterns
    let versioning_patterns = vec![
        ApiPattern {
            _name: "Version Annotation".to_string(),
            pattern: Regex::new(r#"@version\s*\(\s*["']([\d.]+)["']\s*\)"#).unwrap(),
            element_type: "version".to_string(),
            visibility_pattern: None,
        },
        ApiPattern {
            _name: "Since Annotation".to_string(),
            pattern: Regex::new(r#"@since\s*\(\s*["']([\d.]+)["']\s*\)"#).unwrap(),
            element_type: "version".to_string(),
            visibility_pattern: None,
        },
        ApiPattern {
            _name: "Deprecated Annotation".to_string(),
            pattern: Regex::new(r"@deprecated|#\[deprecated\]|@Deprecated").unwrap(),
            element_type: "deprecated".to_string(),
            visibility_pattern: None,
        },
    ];
    self.patterns
        .insert("versioning".to_string(), versioning_patterns);

    // Breaking change patterns
    let breaking_change_patterns = vec![
        ApiPattern {
            _name: "Parameter Change".to_string(),
            pattern: Regex::new(r"(?m)fn\s+\w+\s*\([^)]*\w+\s*:\s*\w+[^)]*\)").unwrap(),
            element_type: "breaking_change".to_string(),
            visibility_pattern: None,
        },
        ApiPattern {
            _name: "Return Type Change".to_string(),
            pattern: Regex::new(r"(?m)fn\s+\w+\s*\([^)]*\)\s*->\s*\w+").unwrap(),
            element_type: "breaking_change".to_string(),
            visibility_pattern: None,
        },
    ];
    self.patterns
        .insert("breaking_changes".to_string(), breaking_change_patterns);

    // Documentation patterns
    let documentation_patterns = vec![
        ApiPattern {
            _name: "Doc Comment".to_string(),
            pattern: Regex::new(r#"(?m)^\s*///.*$|^\s*#.*$|^\s*""".*?""""#).unwrap(),
            element_type: "documentation".to_string(),
            visibility_pattern: None,
        },
        ApiPattern {
            _name: "Missing Documentation".to_string(),
            pattern: Regex::new(r#"(?m)^(pub\s+)?(?:fn|class|struct)\s+\w+"#).unwrap(),
            element_type: "missing_docs".to_string(),
            visibility_pattern: Some(Regex::new(r"^pub\s+").unwrap()),
        },
    ];
    self.patterns
        .insert("documentation".to_string(), documentation_patterns);

    // Compatibility patterns
    let compatibility_patterns = vec![
        ApiPattern {
            _name: "Generic Type".to_string(),
            pattern: Regex::new(
                r"<[A-Z]\w*(?:\s*:\s*\w+)?(?:\s*,\s*[A-Z]\w*(?:\s*:\s*\w+)?)*>",
            )
            .unwrap(),
            element_type: "generic".to_string(),
            visibility_pattern: None,
        },
        ApiPattern {
            _name: "Optional Parameter".to_string(),
            pattern: Regex::new(r"\w+\s*:\s*Option<\w+>|\w+\s*=\s*\w+").unwrap(),
            element_type: "optional".to_string(),
            visibility_pattern: None,
        },
    ];
    self.patterns
        .insert("compatibility".to_string(), compatibility_patterns);
}

    let mut elements = Vec::new();

    let target_types = if analysis_types.contains(&"all".to_string()) {
        self.patterns.keys().cloned().collect::<Vec<_>>()
    } else {
        analysis_types.to_vec()
    };

    for analysis_type in target_types {
        if let Some(patterns) = self.patterns.get(&analysis_type) {
            for pattern in patterns {
                for captures in pattern.pattern.captures_iter(content) {
                    let full_match = captures.get(0).unwrap().as_str();
                    let name = captures
                        .get(2)
                        .or_else(|| captures.get(1))
                        .map(|m| m.as_str())
                        .unwrap_or("unknown");

                    let is_public =
                        if let Some(visibility_pattern) = &pattern.visibility_pattern {
                            visibility_pattern.is_match(full_match)
                        } else {
                            true // Assume public if no visibility pattern
                        };

                    if is_public || include_private_apis {
                        elements.push(ApiElement {
                            element_type: pattern.element_type.clone(),
                            name: name.to_string(),
                            visibility: if is_public {
                                "public".to_string()
                            } else {
                                "private".to_string()
                            },
                            signature: Some(full_match.to_string()),
                            documentation: self.extract_documentation(content, full_match),
                            deprecated: self.is_deprecated(content, full_match),
                            breaking_change_risk: self
                                .assess_breaking_change_risk(&pattern.element_type),
                        });
                    }
                }
            }
        }
    }

    Ok(elements)
}

    // Look for documentation comments above the element
    let lines: Vec<&str> = content.lines().collect();
    for (i, line) in lines.iter().enumerate() {
        if line.contains(element) {
            // Look backwards for documentation
            let mut docs = Vec::new();
            for j in (0..i).rev() {
                let prev_line = lines[j].trim();
                if prev_line.starts_with("///")
                    || prev_line.starts_with("#")
                    || prev_line.starts_with("\"\"\"")
                {
                    docs.insert(0, prev_line);
                } else if !prev_line.is_empty() {
                    break;
                }
            }
            if !docs.is_empty() {
                return Some(docs.join("\n"));
            }
        }
    }
    None
}

    let lines: Vec<&str> = content.lines().collect();
    for (i, line) in lines.iter().enumerate() {
        if line.contains(element) {
            // Look backwards for deprecation annotations
            for j in (0..i).rev() {
                let prev_line = lines[j].trim();
                if prev_line.contains("@deprecated")
                    || prev_line.contains("#[deprecated]")
                    || prev_line.contains("@Deprecated")
                {
                    return true;
                } else if !prev_line.is_empty()
                    && !prev_line.starts_with("///")
                    && !prev_line.starts_with("#")
                {
                    break;
                }
            }
        }
    }
    false
}

    match element_type {
        "function" | "method" => "medium".to_string(),
        "class" | "struct" => "high".to_string(),
        "constant" => "low".to_string(),
        "generic" => "high".to_string(),
        _ => "low".to_string(),
    }
}

    // Simple heuristic - in practice, this would be more sophisticated
    !name.starts_with('_') && !name.starts_with("internal") && !name.starts_with("private")
}

    let mut recommendations = Vec::new();

    if elements.is_empty() {
        recommendations.push(
            "No API elements detected. Consider defining clear public interfaces.".to_string(),
        );
        return recommendations;
    }

    // Count different types of issues
    let public_elements = elements.iter().filter(|e| e.visibility == "public").count();
    let documented_elements = elements
        .iter()
        .filter(|e| e.documentation.is_some())
        .count();
    let deprecated_elements = elements.iter().filter(|e| e.deprecated).count();

    if public_elements > 0 {
        let documentation_coverage =
            (documented_elements as f64 / public_elements as f64) * 100.0;

        if documentation_coverage < 80.0 {
            recommendations.push(format!(
                "API documentation coverage is {documentation_coverage:.1}%. Consider documenting more public APIs."
            ));
        }
    }

    if deprecated_elements > 0 {
        recommendations.push(format!(
            "{deprecated_elements} deprecated API elements found. Plan migration strategy for users."
        ));
    }

    // Check for high-risk breaking changes
    let high_risk_elements = elements
        .iter()
        .filter(|e| e.breaking_change_risk == "high")
        .count();
    if high_risk_elements > 0 {
        recommendations.push(format!(
            "{high_risk_elements} high-risk API elements detected. Changes to these may break compatibility."
        ));
    }

    recommendations.push("Use semantic versioning for API changes.".to_string());
    recommendations.push("Consider API versioning strategy for major changes.".to_string());
    recommendations.push("Implement API compatibility testing.".to_string());
    recommendations.push("Document API lifecycle and deprecation policies.".to_string());

    recommendations
}

    let elements = self.analyze_api_surface(content, &["public_api".to_string()], false)?;

    Ok(elements
        .into_iter()
        .map(|e| {
            serde_json::json!({
                "type": e.element_type,
                "name": e.name,
                "visibility": e.visibility,
                "signature": e.signature,
                "documented": e.documentation.is_some(),
                "deprecated": e.deprecated,
                "breaking_change_risk": e.breaking_change_risk
            })
        })
        .collect())
}

    let elements = self.analyze_api_surface(content, &["versioning".to_string()], true)?;

    Ok(elements
        .into_iter()
        .map(|e| {
            serde_json::json!({
                "type": e.element_type,
                "name": e.name,
                "signature": e.signature,
                "deprecated": e.deprecated
            })
        })
        .collect())
}

    let elements =
        self.analyze_api_surface(content, &["breaking_changes".to_string()], false)?;

    Ok(elements
        .into_iter()
        .map(|e| {
            serde_json::json!({
                "type": e.element_type,
                "name": e.name,
                "signature": e.signature,
                "risk_level": e.breaking_change_risk,
                "recommendation": match e.breaking_change_risk.as_str() {
                    "high" => "Major version bump recommended",
                    "medium" => "Minor version bump may be needed",
                    _ => "Patch version acceptable"
                }
            })
        })
        .collect())
}

    let elements = self.analyze_api_surface(content, &["public_api".to_string()], false)?;

    let total_public = elements.len();
    let documented = elements
        .iter()
        .filter(|e| e.documentation.is_some())
        .count();
    let coverage = if total_public > 0 {
        (documented as f64 / total_public as f64) * 100.0
    } else {
        100.0
    };

    Ok(vec![serde_json::json!({
        "total_public_apis": total_public,
        "documented_apis": documented,
        "coverage_percentage": coverage,
        "undocumented_apis": elements.into_iter()
            .filter(|e| e.documentation.is_none())
            .map(|e| serde_json::json!({
                "name": e.name,
                "type": e.element_type,
                "signature": e.signature
            }))
            .collect::<Vec<_>>()
    })])
}

    let analyzer = ApiSurfaceAnalyzer::new();

    let code = "pub fn test_function(x: i32) -> i32 { x + 1 }";
    let elements = analyzer
        .analyze_api_surface(code, &["public_api".to_string()], false)
        .unwrap();

    assert!(!elements.is_empty(), "Should find API surface elements");

    // Verify elements contain the expected API surface
    assert!(!elements.is_empty(), "Should have at least one API element");
    assert!(
        elements
            .iter()
            .any(|e| e.name == "test_function" && e.visibility == "public"),
        "Should find public test_function"
    );

    // Verify element structure is meaningful
    let test_func = elements
        .iter()
        .find(|e| e.name == "test_function")
        .expect("Should have test_function");
    assert!(
        test_func.signature.is_some() && !test_func.signature.as_ref().unwrap().is_empty(),
        "Function should have signature"
    );
    assert!(
        !test_func.element_type.is_empty(),
        "Function should have element type"
    );
}

    let analyzer = ApiSurfaceAnalyzer::new();

    let code = "#[deprecated]\npub fn old_function() {}";
    let elements = analyzer
        .analyze_api_surface(code, &["public_api".to_string()], false)
        .unwrap();

    assert!(!elements.is_empty(), "Should not be empty");
    assert!(elements.iter().any(|e| e.deprecated));
}

    let analyzer = ApiSurfaceAnalyzer::new();

    let code = "/// This is a test function\npub fn documented_function() {}";
    let elements = analyzer
        .analyze_api_surface(code, &["public_api".to_string()], false)
        .unwrap();

    assert!(!elements.is_empty(), "Should not be empty");
    assert!(elements.iter().any(|e| e.documentation.is_some()));
}

    let analyzer = ApiSurfaceAnalyzer::new();

    assert_eq!(analyzer.assess_breaking_change_risk("class"), "high");
    assert_eq!(analyzer.assess_breaking_change_risk("function"), "medium");
    assert_eq!(analyzer.assess_breaking_change_risk("constant"), "low");
}

    let analyzer = ApiSurfaceAnalyzer::new();

    assert!(analyzer.is_public_api_element("public_function"));
    assert!(!analyzer.is_public_api_element("_private_function"));
    assert!(!analyzer.is_public_api_element("internal_function"));
}

    let analyzer = ApiSurfaceAnalyzer::new();

    let elements = vec![ApiElement {
        element_type: "function".to_string(),
        name: "test".to_string(),
        visibility: "public".to_string(),
        signature: None,
        documentation: None,
        deprecated: false,
        breaking_change_risk: "medium".to_string(),
    }];

    let recommendations = analyzer.get_api_recommendations(&elements);
    assert!(!recommendations.is_empty(), "Should not be empty");
}

    let content = std::fs::read_to_string(file_path)?;
    let lines_count = content.lines().count();

    let complexity_metrics = self.calculate_all_metrics(&content, lines_count);

    let mut result = serde_json::json!({
        "file": file_path.display().to_string(),
        "lines_of_code": lines_count,
        "metrics": {}
    });

    if metrics.contains(&"cyclomatic".to_string()) || metrics.contains(&"all".to_string()) {
        result["metrics"]["cyclomatic_complexity"] = complexity_metrics.cyclomatic.into();
        if threshold_warnings && complexity_metrics.cyclomatic > 10 {
            result["warnings"] = serde_json::json!([{
                "type": "high_cyclomatic_complexity",
                "message": format!("Cyclomatic complexity ({}) exceeds recommended threshold (10)", complexity_metrics.cyclomatic)
            }]);
        }
    }

    if metrics.contains(&"cognitive".to_string()) || metrics.contains(&"all".to_string()) {
        result["metrics"]["cognitive_complexity"] = complexity_metrics.cognitive.into();
        if threshold_warnings && complexity_metrics.cognitive > 15 {
            let warnings = result["warnings"].as_array().cloned().unwrap_or_default();
            let mut new_warnings = warnings;
            new_warnings.push(serde_json::json!({
                "type": "high_cognitive_complexity",
                "message": format!("Cognitive complexity ({}) exceeds recommended threshold (15)", complexity_metrics.cognitive)
            }));
            result["warnings"] = new_warnings.into();
        }
    }

    if metrics.contains(&"halstead".to_string()) || metrics.contains(&"all".to_string()) {
        result["metrics"]["halstead"] = serde_json::json!({
            "volume": complexity_metrics.halstead_volume,
            "difficulty": complexity_metrics.halstead_difficulty,
            "effort": complexity_metrics.halstead_effort
        });
    }

    if metrics.contains(&"maintainability".to_string()) || metrics.contains(&"all".to_string())
    {
        result["metrics"]["maintainability_index"] =
            complexity_metrics.maintainability_index.into();
        if threshold_warnings && complexity_metrics.maintainability_index < 50.0 {
            let warnings = result["warnings"].as_array().cloned().unwrap_or_default();
            let mut new_warnings = warnings;
            new_warnings.push(serde_json::json!({
                "type": "low_maintainability",
                "message": format!("Maintainability index ({:.1}) is below recommended threshold (50.0)", complexity_metrics.maintainability_index)
            }));
            result["warnings"] = new_warnings.into();
        }
    }

    Ok(result)
}

    let cyclomatic = self.calculate_cyclomatic_complexity(content);
    let cognitive = self.calculate_cognitive_complexity(content);
    let (halstead_volume, halstead_difficulty, halstead_effort) =
        self.calculate_halstead_metrics(content);
    let maintainability_index = self.calculate_maintainability_index(content, lines_count);

    ComplexityMetrics {
        cyclomatic,
        cognitive,
        halstead_volume,
        halstead_difficulty,
        halstead_effort,
        maintainability_index,
        lines_of_code: lines_count,
    }
}

    let mut complexity = 1; // Base complexity

    // Count decision points (simplified heuristic)
    let decision_keywords = [
        "if", "else if", "elif", "while", "for", "foreach", "switch", "case", "catch",
        "except", "?", "&&", "||", "and", "or",
    ];

    for keyword in &decision_keywords {
        complexity += content.matches(keyword).count();
    }

    complexity
}

    let mut complexity = 0;
    let mut nesting_level: usize = 0;

    let lines = content.lines();
    for line in lines {
        let trimmed = line.trim();

        // Increment nesting for certain constructs
        if trimmed.contains('{')
            || trimmed.starts_with("if ")
            || trimmed.starts_with("for ")
            || trimmed.starts_with("while ")
            || trimmed.starts_with("try ")
            || trimmed.starts_with("def ")
            || trimmed.starts_with("function ")
        {
            nesting_level += 1;
        }

        // Decrement nesting
        if trimmed.contains('}') {
            nesting_level = nesting_level.saturating_sub(1usize);
        }

        // Add complexity based on constructs
        if trimmed.contains("if ") || trimmed.contains("elif ") || trimmed.contains("else if") {
            complexity += 1 + nesting_level;
        }
        if trimmed.contains("while ") || trimmed.contains("for ") {
            complexity += 1 + nesting_level;
        }
        if trimmed.contains("catch ") || trimmed.contains("except ") {
            complexity += 1 + nesting_level;
        }
    }

    complexity
}

    // Simplified Halstead calculation
    let operators = [
        "=", "+", "-", "*", "/", "==", "!=", "<", ">", "<=", ">=", "&&", "||",
    ];
    let mut unique_operators = HashSet::new();
    let mut total_operators = 0;

    for op in &operators {
        let count = content.matches(op).count();
        if count > 0 {
            unique_operators.insert(op);
            total_operators += count;
        }
    }

    // Rough operand estimation (identifiers, literals)
    let words: Vec<&str> = content.split_whitespace().collect();
    let mut unique_operands = HashSet::new();
    let mut total_operands = 0;

    for word in words {
        if word.chars().any(|c| c.is_alphanumeric()) {
            unique_operands.insert(word);
            total_operands += 1;
        }
    }

    let n1 = unique_operators.len().max(1) as f64; // Minimum 1 operator
    let n2 = unique_operands.len().max(1) as f64; // Minimum 1 operand
    let big_n1 = total_operators.max(1) as f64; // Minimum 1 operator usage
    let big_n2 = total_operands.max(1) as f64; // Minimum 1 operand usage

    let vocabulary = n1 + n2;
    let length = big_n1 + big_n2;

    // Ensure vocabulary is at least 2 to avoid log2(1) = 0
    let safe_vocabulary = vocabulary.max(2.0);
    let volume = length * safe_vocabulary.log2();

    // Safe difficulty calculation
    let difficulty = (n1 / 2.0) * (big_n2 / n2);
    let effort = difficulty * volume;

    (volume, difficulty, effort)
}

    let (volume, difficulty, _effort) = self.calculate_halstead_metrics(content);
    let cyclomatic = self.calculate_cyclomatic_complexity(content) as f64;
    let loc = lines_count.max(1) as f64; // Minimum 1 line

    // Ensure volume is meaningful for logarithm
    let safe_volume = volume.max(1.0);
    let safe_loc = loc.max(1.0);

    // Adjusted maintainability index formula to be more sensitive
    // Based on the standard formula but with adjusted coefficients for this simplified implementation
    // Higher volume, complexity, and difficulty should decrease maintainability more significantly
    let volume_penalty = safe_volume.ln() * 8.0; // Increased from 5.2
    let complexity_penalty = cyclomatic * 5.0; // Increased from 0.23
    let loc_penalty = safe_loc.ln() * 20.0; // Increased from 16.2
    let difficulty_penalty = difficulty * 2.0; // Add difficulty factor

    let mi = 171.0 - volume_penalty - complexity_penalty - loc_penalty - difficulty_penalty;

    // Ensure result is in valid range
    mi.clamp(0.0, 100.0)
}

    let analyzer = ComplexityAnalyzer::new();

    let simple_code = "function test() { return 1; }";
    assert_eq!(analyzer.calculate_cyclomatic_complexity(simple_code), 1);

    let complex_code = "if (x) { if (y) { while (z) { for (i in items) { } } } }";
    assert!(analyzer.calculate_cyclomatic_complexity(complex_code) > 1);
}

    let analyzer = ComplexityAnalyzer::new();

    let simple_code = "function test() { return 1; }";
    assert_eq!(analyzer.calculate_cognitive_complexity(simple_code), 0);

    let nested_code = "if (x) {\n  if (y) {\n    while (z) {\n    }\n  }\n}";
    assert!(analyzer.calculate_cognitive_complexity(nested_code) > 0);
}

    let analyzer = ComplexityAnalyzer::new();

    let code = "x = a + b * c";
    let (volume, difficulty, effort) = analyzer.calculate_halstead_metrics(code);

    assert!(volume > 0.0);
    assert!(difficulty > 0.0);
    assert!(effort > 0.0);
}

    let analyzer = ComplexityAnalyzer::new();

    let simple_code = "function test() { return 1; }";
    let mi = analyzer.calculate_maintainability_index(simple_code, 1);

    assert!((0.0..=100.0).contains(&mi));
}

    let mut analyzer = Self {
        ast_cache: HashMap::new(),
        semantic_patterns: HashMap::new(),
        language_analyzers: HashMap::new(),
    };
    analyzer.initialize_language_analyzers();
    analyzer.initialize_semantic_patterns();
    analyzer
}

    let mut duplicates = Vec::new();
    let mut file_contents = HashMap::new();
    let mut file_asts = HashMap::new();

    // Collect all source files and parse them
    for entry in WalkDir::new(repo_path)
        .into_iter()
        .filter_map(|e| e.ok())
        .filter(|e| e.file_type().is_file())
    {
        let path = entry.path();
        if let Some(ext) = path.extension().and_then(|e| e.to_str()) {
            if [
                "js", "ts", "py", "java", "rs", "c", "cpp", "go", "rb", "php",
            ]
            .contains(&ext)
            {
                let path_str = path.to_string_lossy();
                if exclude_patterns
                    .iter()
                    .any(|pattern| path_str.contains(pattern))
                {
                    continue;
                }

                if let Ok(content) = std::fs::read_to_string(path) {
                    let lines = content.lines().count();
                    if lines >= min_lines {
                        // Parse AST for the file
                        let ast = self.parse_file_ast(&content, ext)?;
                        file_asts.insert(path.to_path_buf(), ast);
                        file_contents.insert(path.to_path_buf(), content);
                    }
                }
            }
        }
    }

    // Advanced duplicate detection using multiple techniques
    duplicates.extend(self.find_exact_duplicates(&file_contents, min_lines)?);
    duplicates.extend(self.find_structural_duplicates(
        &file_asts,
        similarity_threshold,
        min_lines,
    )?);
    duplicates.extend(self.find_semantic_duplicates(
        &file_contents,
        similarity_threshold,
        min_lines,
    )?);
    duplicates.extend(self.find_pattern_duplicates(&file_contents, similarity_threshold)?);

    // Remove overlapping duplicates and enhance with refactoring suggestions
    let deduplicated = self.deduplicate_results(duplicates);
    let enhanced_results = deduplicated
        .into_iter()
