            '{' => regex.push_str("\\{"),
            '}' => regex.push_str("\\}"),
            '|' => regex.push_str("\\|"),
            '\\' => regex.push_str("\\\\"),
            c => regex.push(c),
        }
    }

    regex.push('$');
