        CircuitState::Closed => {
            // Reset failure count in closed state
            state.failure_count = 0;
        }
        CircuitState::HalfOpen => {
            state.success_count += 1;
            if state.success_count >= self.config.success_threshold {
                // Transition to closed
                state.circuit_state = CircuitState::Closed;
                state.failure_count = 0;
                state.success_count = 0;
                state.last_transition_time = now;
                info!("Circuit breaker closed - service recovered");
            }
        }
        CircuitState::Open => {
            // Should not happen, but reset if it does
            warn!("Recording success in open circuit state");
        }
    }
}

    let mut state = self.state.lock().unwrap();
    let now = Instant::now();

    state.last_failure_time = Some(now);

    match state.circuit_state {
        CircuitState::Closed => {
            state.failure_count += 1;
            if state.failure_count >= self.config.failure_threshold {
                // Transition to open
                state.circuit_state = CircuitState::Open;
                state.last_transition_time = now;
                error!(
                    "Circuit breaker opened due to {} failures",
                    state.failure_count
                );
            }
        }
        CircuitState::HalfOpen => {
            // Go back to open
            state.circuit_state = CircuitState::Open;
            state.failure_count += 1;
            state.success_count = 0;
            state.last_transition_time = now;
            warn!("Circuit breaker returned to open state");
        }
        CircuitState::Open => {
            state.failure_count += 1;
        }
    }
}

    let mut last_error = None;

    for attempt in 0..self.config.max_attempts {
        debug!(
            "Executing operation, attempt {}/{}",
            attempt + 1,
            self.config.max_attempts
        );

        match operation().await {
            Ok(result) => {
                if attempt > 0 {
                    info!("Operation succeeded after {} retries", attempt);
                }
                return Ok(result);
            }
            Err(error) => {
                last_error = Some(error.clone());

                if !error.should_retry() {
                    debug!("Error is not retryable: {}", error);
                    return Err(error);
                }

                if attempt + 1 >= self.config.max_attempts {
                    error!(
                        "Operation failed after {} attempts: {}",
                        self.config.max_attempts, error
                    );
                    break;
                }

                let delay = self.config.calculate_delay(attempt);
                warn!(
                    "Operation failed (attempt {}), retrying in {:?}: {}",
                    attempt + 1,
                    delay,
                    error
                );

                sleep(delay).await;
            }
        }
    }

    Err(last_error.unwrap_or_else(|| Error::other("Unknown retry error")))
}

    Self {
        retry_executor: RetryExecutor::new(retry_config),
        circuit_breaker: CircuitBreaker::new(circuit_config),
    }
}

    if !self.circuit_breaker.can_execute() {
