    }

    let result = self
        .retry_executor
        .execute(|| {
            let op = operation.clone();
            async move { op().await }
        })
        .await;

    match &result {
        Ok(_) => self.circuit_breaker.record_success(),
        Err(error) => {
            if matches!(
                error.severity(),
                ErrorSeverity::Error | ErrorSeverity::Critical
            ) {
                self.circuit_breaker.record_failure();
            }
        }
    }

    result
}

