    let executor = RetryExecutor::new(RetryConfig::new(3, Duration::from_millis(10)));

    let attempts = std::sync::Arc::new(std::sync::atomic::AtomicUsize::new(0));
    let attempts_clone = attempts.clone();

    let result = executor
        .execute(|| {
            let current_attempt =
                attempts_clone.fetch_add(1, std::sync::atomic::Ordering::SeqCst) + 1;
            async move {
                if current_attempt < 2 {
                    Err(Error::storage("temporary failure"))
                } else {
                    Ok("success")
                }
            }
        })
        .await;

    assert!(result.is_ok(), "Resilience operation should succeed");
    assert_eq!(result.unwrap(), "success");
    assert_eq!(attempts.load(std::sync::atomic::Ordering::SeqCst), 2);
}

