    let autowired_regex = Regex::new(
        r"@Autowired\s+(?:private\s+|protected\s+|public\s+)?(\w+(?:<[^>]+>)?)\s+(\w+)",
    )
    .unwrap();

    for captures in autowired_regex.captures_iter(&class_content) {
