    }

    // Store the mapping
    self.node_map.insert(node.id(), func_node.id);

    // Add edge from module/class to function
    if let Some(parent_id) = self.find_parent_node_id(&node) {
        self.edges
            .push(Edge::new(parent_id, func_node.id, EdgeKind::Calls));
