        .file_path
        .file_stem()
        .and_then(|s| s.to_str())
        .unwrap_or("module")
        .to_string();

    let node = Node::new(
        &self.repo_id,
        NodeKind::Module,
        module_name,
        self.language,
        self.file_path.clone(),
