    );

    self.node_map.insert(root.id(), node.id);
    Ok(node)
}

    self.visit_node(cursor)?;

    if cursor.goto_first_child() {
        loop {
            self.walk_tree(cursor)?;
            if !cursor.goto_next_sibling() {
                break;
            }
        }
        cursor.goto_parent();
    }

    Ok(())
}

    let node = cursor.node();
    let kind = node.kind();

