        let context_lower = ctx.to_lowercase();
        if content_lower.contains(&context_lower) {
            relevance += 0.3;
        }
    }

    // Length and complexity factors
    if content.len() > 50 && content.len() < 500 {
        relevance += 0.1; // Prefer moderate-length content
    }

    relevance.min(1.0f32)
