        let deserialized: Transport = serde_json::from_str(&json).unwrap();

        match (&transport, &deserialized) {
            (Transport::Stdio, Transport::Stdio) => {}
            (Transport::Http { url: url1 }, Transport::Http { url: url2 }) => {
